SELECT DISTINCT s.patient_id
FROM access_logs a
INNER JOIN samples s ON a.sample_id = s.sample_id;

SELECT COUNT(DISTINCT patient_id) AS unique_patients
FROM samples
WHERE drug_name = '1';

SELECT COUNT(DISTINCT sample_id) AS unique_samples
FROM samples
WHERE tier > 1 AND census_gene = 'Yes' AND drug_name IS NOT NULL;

SELECT sample_name
FROM samples
ORDER BY collection_date DESC;

SELECT DISTINCT patient_id
FROM samples
WHERE drug_name = 'SpecificDrugName';

SELECT trial_id
FROM clinical_trials
WHERE drug_name = 'Tyrosine kinase inhibitor - NS';
